from hash import G, H, J

def test_G():
    d = bytes.fromhex("f688563f7c66a5da2d8bdb5a5f3e07bd8dce6f7efcec7f41298d79863459f7cd")
    rho, sigma = G(d)
    assert rho == bytes.fromhex("26ffff11b531b1800f4e1fa75c4d008c4f9a112932c669d543551204405da8b4")
    assert sigma == bytes.fromhex("6de0c01beda8a2ba3f697c1bb8d5a46dc2ac63880c4f9b57db9f10534cef9a42")

def test_H():
    ek = bytes.fromhex("")
    h = H(ek)
    expected_h = bytes.fromhex("704649a5d8034c6224ae18950bd7b979342c03c7499f7bab9cdea742db9e086c")
    assert h == expected_h

def test_J():
    z = bytes.fromhex("d1d49a515250dbceb9f6e3fcc1c7d5306918964b21ddb22207e03e57f0600da8")
    c = bytes.fromhex("")
    K_bar = J(z + c)
    expected_K_bar = bytes.fromhex("2f3eac7d224d818aceb416748cf117f7f61a8554e8b2b6522fdcc6dfb37e9995")
    assert K_bar == expected_K_bar